     1→<!DOCTYPE html>
     2→<html lang="en">
     3→<head>
     4→  <meta charset="UTF-8">
     5→  <meta name="viewport" content="width=device-width, initial-scale=1.0">
     6→  <title>Job Board - Rekrut AI</title>
     7→  <link rel="preconnect" href="https://fonts.googleapis.com">
     8→  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
     9→  <link href="https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;500;600;700&family=Inter:wght@400;500;600&display=swap" rel="stylesheet">
    10→  <link rel="stylesheet" href="/css/styles.css">
    11→  <link rel="stylesheet" href="/css/responsive.css">
    12→  <link rel="stylesheet" href="/css/dashboard.css">
    13→</head>
    14→<body>
    15→  <div class="dashboard-layout">
    16→    <!-- Sidebar -->
    17→    <aside class="sidebar">
    18→      <a href="/" class="logo">
    19→        <span class="logo-icon">◎</span>
    20→        <span>Rekrut AI</span>
    21→      </a>
    22→
    23→      <nav class="sidebar-nav">
    24→        <a href="/candidate-dashboard.html" class="nav-item">
    25→          <span class="nav-icon">🏠</span>
    26→          <span>Dashboard</span>
    27→        </a>
    28→        <a href="/candidate-profile.html" class="nav-item">
    29→          <span class="nav-icon">👤</span>
    30→          <span>My Profile</span>
    31→        </a>
    32→        <a href="/omniscore.html" class="nav-item">
    33→          <span class="nav-icon">🎯</span>
    34→          <span>OmniScore</span>
    35→        </a>
    36→        <a href="/skill-assessments.html" class="nav-item">
    37→          <span class="nav-icon">📝</span>
    38→          <span>Skill Tests</span>
    39→        </a>
    40→        <a href="/interview.html" class="nav-item">
    41→          <span class="nav-icon">🎤</span>
    42→          <span>Interview Prep</span>
    43→        </a>
    44→        <a href="/job-board.html" class="nav-item active">
    45→          <span class="nav-icon">💼</span>
    46→          <span>Job Board</span>
    47→        </a>
    48→      </nav>
    49→
    50→      <div class="sidebar-footer">
    51→        <button onclick="handleLogout()" class="btn btn-ghost btn-sm btn-full">Logout</button>
    52→      </div>
    53→    </aside>
    54→
    55→    <!-- Main Content -->
    56→    <main class="main-content">
    57→      <header class="page-header">
    58→        <div>
    59→          <h1>Job Board</h1>
    60→          <p>Jobs matched to your OmniScore and skills</p>
    61→        </div>
    62→        <div class="header-stats">
    63→          <div class="mini-score">
    64→            <span class="mini-score-value" id="user-omniscore">---</span>
    65→            <span class="mini-score-label">Your OmniScore</span>
    66→          </div>
    67→        </div>
    68→      </header>
    69→
    70→      <!-- Tabs -->
    71→      <div class="job-tabs">
    72→        <button class="tab-btn active" data-tab="recommended" onclick="switchTab('recommended')">
    73→          <span>🎯</span> Recommended
    74→        </button>
    75→        <button class="tab-btn" data-tab="all" onclick="switchTab('all')">
    76→          <span>📋</span> All Jobs
    77→        </button>
    78→        <button class="tab-btn" data-tab="saved" onclick="switchTab('saved')">
    79→          <span>❤️</span> Saved <span class="tab-count" id="saved-count">0</span>
    80→        </button>
    81→        <button class="tab-btn" data-tab="applications" onclick="switchTab('applications')">
    82→          <span>📄</span> Applied <span class="tab-count" id="applied-count">0</span>
    83→        </button>
    84→      </div>
    85→
    86→      <!-- Filters (for recommended/all) -->
    87→      <div class="job-filters" id="job-filters">
    88→        <div class="filter-group">
    89→          <label>Location</label>
    90→          <select id="filter-location" onchange="applyFilters()">
    91→            <option value="">All Locations</option>
    92→            <option value="remote">Remote</option>
    93→            <option value="san francisco">San Francisco</option>
    94→            <option value="new york">New York</option>
    95→            <option value="austin">Austin</option>
    96→            <option value="seattle">Seattle</option>
    97→          </select>
    98→        </div>
    99→        <div class="filter-group">
   100→          <label>Job Type</label>
   101→          <select id="filter-type" onchange="applyFilters()">
   102→            <option value="">All Types</option>
   103→            <option value="full-time">Full-time</option>
   104→            <option value="part-time">Part-time</option>
   105→            <option value="contract">Contract</option>
   106→            <option value="internship">Internship</option>
   107→          </select>
   108→        </div>
   109→        <div class="filter-group">
   110→          <label>Match Score</label>
   111→          <select id="filter-match" onchange="applyFilters()">
   112→            <option value="">Any Match</option>
   113→            <option value="80">80%+ (Excellent)</option>
   114→            <option value="60">60%+ (Good)</option>
   115→            <option value="40">40%+ (Fair)</option>
   116→          </select>
   117→        </div>
   118→      </div>
   119→
   120→      <!-- Job Listings -->
   121→      <div class="jobs-container" id="jobs-container">
   122→        <div class="loading-state">
   123→          <div class="spinner"></div>
   124→          <p>Finding jobs for you...</p>
   125→        </div>
   126→      </div>
   127→
   128→      <!-- Job Detail Modal -->
   129→      <div class="job-detail-panel" id="job-detail-panel">
   130→        <div class="job-detail-content" id="job-detail-content">
   131→          <!-- Job details rendered here -->
   132→        </div>
   133→      </div>
   134→    </main>
   135→  </div>
   136→
   137→  <!-- Application Modal -->
   138→  <div class="modal-overlay" id="modal-overlay" onclick="closeModal()"></div>
   139→  <div class="modal" id="apply-modal">
   140→    <div class="modal-header">
   141→      <h3>Apply to <span id="apply-job-title"></span></h3>
   142→      <button class="modal-close" onclick="closeModal()">&times;</button>
   143→    </div>
   144→    <div class="modal-body">
   145→      <div class="apply-match-preview">
   146→        <div class="match-circle" id="apply-match-circle">
   147→          <span id="apply-match-score">0%</span>
   148→        </div>
   149→        <div class="match-info">
   150→          <span class="match-level" id="apply-match-level">Good Match</span>
   151→          <span class="match-desc" id="apply-match-desc">Based on your skills and experience</span>
   152→        </div>
   153→      </div>
   154→
   155→      <div class="form-group">
   156→        <label>Cover Letter (Optional)</label>
   157→        <textarea id="cover-letter" rows="6" placeholder="Tell them why you're a great fit for this role..."></textarea>
   158→      </div>
   159→
   160→      <div class="apply-checklist">
   161→        <h4>Your Application Includes:</h4>
   162→        <ul>
   163→          <li><span class="check">✓</span> Your OmniScore</li>
   164→          <li><span class="check">✓</span> Profile & Experience</li>
   165→          <li><span class="check">✓</span> Skills & Assessments</li>
   166→          <li><span class="check" id="resume-check">✓</span> Resume (if uploaded)</li>
   167→        </ul>
   168→      </div>
   169→    </div>
   170→    <div class="modal-footer">
   171→      <button class="btn btn-ghost" onclick="closeModal()">Cancel</button>
   172→      <button class="btn btn-primary" id="submit-apply-btn" onclick="submitApplication()">Submit Application</button>
   173→    </div>
   174→  </div>
   175→
   176→  <script src="/js/main.js"></script>
   177→  <script>
   178→    let allJobs = [];
   179→    let savedJobs = [];
   180→    let applications = [];
   181→    let currentTab = 'recommended';
   182→    let selectedJobId = null;
   183→
   184→    document.addEventListener('DOMContentLoaded', async () => {
   185→      const user = await checkAuth();
   186→      if (!user) {
   187→        window.location.href = '/login.html';
   188→        return;
   189→      }
   190→
   191→      loadOmniScore();
   192→      loadJobs();
   193→      loadSavedJobs();
   194→      loadApplications();
   195→    });
   196→
   197→    async function loadOmniScore() {
   198→      try {
   199→        const data = await apiCall('/omniscore');
   200→        if (data.success && data.omniscore) {
   201→          document.getElementById('user-omniscore').textContent = data.omniscore.total_score;
   202→        }
   203→      } catch (err) {
   204→        document.getElementById('user-omniscore').textContent = '300';
   205→      }
   206→    }
   207→
   208→    async function loadJobs() {
   209→      try {
   210→        const data = await apiCall('/candidate/jobs/recommended?limit=30');
   211→        if (data.success) {
   212→          allJobs = data.jobs;
   213→          renderJobs(data.jobs);
   214→        }
   215→      } catch (err) {
   216→        console.error('Load jobs error:', err);
   217→        document.getElementById('jobs-container').innerHTML = `
   218→          <div class="empty-state">
   219→            <p>Could not load jobs. Please try again.</p>
   220→          </div>
   221→        `;
   222→      }
   223→    }
   224→
   225→    async function loadSavedJobs() {
   226→      try {
   227→        const data = await apiCall('/candidate/jobs/saved');
   228→        if (data.success) {
   229→          savedJobs = data.jobs;
   230→          document.getElementById('saved-count').textContent = data.jobs.length;
   231→        }
   232→      } catch (err) {
   233→        console.error('Load saved jobs error:', err);
   234→      }
   235→    }
   236→
   237→    async function loadApplications() {
   238→      try {
   239→        const data = await apiCall('/candidate/applications');
   240→        if (data.success) {
   241→          applications = data.applications;
   242→          document.getElementById('applied-count').textContent = data.applications.length;
   243→        }
   244→      } catch (err) {
   245→        console.error('Load applications error:', err);
   246→      }
   247→    }
   248→
   249→    function switchTab(tab) {
   250→      currentTab = tab;
   251→
   252→      document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
   253→      document.querySelector(`[data-tab="${tab}"]`).classList.add('active');
   254→
   255→      // Show/hide filters
   256→      document.getElementById('job-filters').style.display =
   257→        (tab === 'recommended' || tab === 'all') ? 'flex' : 'none';
   258→
   259→      // Close detail panel
   260→      document.getElementById('job-detail-panel').classList.remove('active');
   261→
   262→      // Render appropriate list
   263→      if (tab === 'recommended') {
   264→        renderJobs(allJobs);
   265→      } else if (tab === 'all') {
   266→        // For all, we show the same but without match info prominently
   267→        renderJobs(allJobs, false);
   268→      } else if (tab === 'saved') {
   269→        renderSavedJobs();
   270→      } else if (tab === 'applications') {
   271→        renderApplications();
   272→      }
   273→    }
   274→
   275→    function applyFilters() {
   276→      const location = document.getElementById('filter-location').value.toLowerCase();
   277→      const type = document.getElementById('filter-type').value;
   278→      const minMatch = parseInt(document.getElementById('filter-match').value) || 0;
   279→
   280→      let filtered = allJobs.filter(job => {
   281→        if (location && job.location && !job.location.toLowerCase().includes(location)) return false;
   282→        if (type && job.job_type !== type) return false;
   283→        if (minMatch && (!job.match || job.match.match_score < minMatch)) return false;
   284→        return true;
   285→      });
   286→
   287→      renderJobs(filtered);
   288→    }
   289→
   290→    function renderJobs(jobs, showMatch = true) {
   291→      const container = document.getElementById('jobs-container');
   292→
   293→      if (!jobs || jobs.length === 0) {
   294→        container.innerHTML = `
   295→          <div class="empty-state">
   296→            <p>No jobs found matching your criteria.</p>
   297→          </div>
   298→        `;
   299→        return;
   300→      }
   301→
   302→      container.innerHTML = `
   303→        <div class="jobs-list">
   304→          ${jobs.map(job => renderJobCard(job, showMatch)).join('')}
   305→        </div>
   306→      `;
   307→    }
   308→
   309→    function renderJobCard(job, showMatch = true) {
   310→      const match = job.match || {};
   311→      const matchScore = match.match_score || 50;
   312→      const matchLevel = match.match_level || 'fair';
   313→      const isSaved = savedJobs.some(s => s.id === job.id);
   314→      const hasApplied = applications.some(a => a.job_id === job.id);
   315→
   316→      return `
   317→        <div class="job-card ${hasApplied ? 'applied' : ''}" onclick="showJobDetail(${job.id})">
   318→          <div class="job-card-main">
   319→            <div class="job-card-header">
   320→              <h3>${job.title}</h3>
   321→              <button class="save-btn ${isSaved ? 'saved' : ''}" onclick="event.stopPropagation(); toggleSave(${job.id})">
   322→                ${isSaved ? '❤️' : '🤍'}
   323→              </button>
   324→            </div>
   325→            <p class="job-company">${job.company || job.posted_by_company || 'Company'}</p>
   326→            <div class="job-meta">
   327→              ${job.location ? `<span class="job-location">📍 ${job.location}</span>` : ''}
   328→              ${job.job_type ? `<span class="job-type">${job.job_type}</span>` : ''}
   329→              ${job.salary_range ? `<span class="job-salary">💰 ${job.salary_range}</span>` : ''}
   330→            </div>
   331→          </div>
   332→          ${showMatch ? `
   333→            <div class="job-card-match">
   334→              <div class="match-indicator ${matchLevel}">
   335→                <span class="match-percent">${matchScore}%</span>
   336→                <span class="match-label">match</span>
   337→              </div>
   338→              ${hasApplied ? '<span class="applied-badge">Applied</span>' : ''}
   339→            </div>
   340→          ` : ''}
   341→        </div>
   342→      `;
   343→    }
   344→
   345→    function renderSavedJobs() {
   346→      const container = document.getElementById('jobs-container');
   347→
   348→      if (savedJobs.length === 0) {
   349→        container.innerHTML = `
   350→          <div class="empty-state">
   351→            <h3>No Saved Jobs</h3>
   352→            <p>Save jobs you're interested in to apply later.</p>
   353→            <button class="btn btn-primary" onclick="switchTab('recommended')">Browse Jobs</button>
   354→          </div>
   355→        `;
   356→        return;
   357→      }
   358→
   359→      container.innerHTML = `
   360→        <div class="jobs-list">
   361→          ${savedJobs.map(job => renderJobCard(job, true)).join('')}
   362→        </div>
   363→      `;
   364→    }
   365→
   366→    function renderApplications() {
   367→      const container = document.getElementById('jobs-container');
   368→
   369→      if (applications.length === 0) {
   370→        container.innerHTML = `
   371→          <div class="empty-state">
   372→            <h3>No Applications Yet</h3>
   373→            <p>Apply to jobs to track your applications here.</p>
   374→            <button class="btn btn-primary" onclick="switchTab('recommended')">Find Jobs</button>
   375→          </div>
   376→        `;
   377→        return;
   378→      }
   379→
   380→      container.innerHTML = `
   381→        <div class="applications-list">
   382→          ${applications.map(app => `
   383→            <div class="application-card" onclick="showJobDetail(${app.job_id})">
   384→              <div class="application-info">
   385→                <h4>${app.title}</h4>
   386→                <p>${app.company || app.posted_by_company || 'Company'}</p>
   387→                <span class="application-date">Applied ${formatDate(app.applied_at)}</span>
   388→              </div>
   389→              <div class="application-status">
   390→                <span class="status-badge ${app.status}">${formatStatus(app.status)}</span>
   391→                ${app.match_score ? `<span class="match-score">${app.match_score}% match</span>` : ''}
   392→              </div>
   393→            </div>
   394→          `).join('')}
   395→        </div>
   396→      `;
   397→    }
   398→
   399→    function formatDate(dateStr) {
   400→      const date = new Date(dateStr);
   401→      return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
   402→    }
   403→
   404→    function formatStatus(status) {
   405→      const labels = {
   406→        'applied': 'Applied',
   407→        'reviewing': 'Under Review',
   408→        'interviewing': 'Interviewing',
   409→        'offered': 'Offer Received',
   410→        'rejected': 'Not Selected',
   411→        'accepted': 'Accepted'
   412→      };
   413→      return labels[status] || status;
   414→    }
   415→
   416→    async function showJobDetail(jobId) {
   417→      selectedJobId = jobId;
   418→      const job = allJobs.find(j => j.id === jobId) ||
   419→                  savedJobs.find(j => j.id === jobId) ||
   420→                  applications.find(a => a.job_id === jobId);
   421→
   422→      if (!job) return;
   423→
   424→      const match = job.match || {};
   425→      const isSaved = savedJobs.some(s => s.id === jobId);
   426→      const hasApplied = applications.some(a => a.job_id === jobId);
   427→
   428→      const panel = document.getElementById('job-detail-panel');
   429→      const content = document.getElementById('job-detail-content');
   430→
   431→      content.innerHTML = `
   432→        <button class="close-panel-btn" onclick="closeDetailPanel()">×</button>
   433→
   434→        <div class="job-detail-header">
   435→          <h2>${job.title}</h2>
   436→          <p class="detail-company">${job.company || job.posted_by_company || 'Company'}</p>
   437→        </div>
   438→
   439→        <div class="job-detail-meta">
   440→          ${job.location ? `<span>📍 ${job.location}</span>` : ''}
   441→          ${job.job_type ? `<span>⏰ ${job.job_type}</span>` : ''}
   442→          ${job.salary_range ? `<span>💰 ${job.salary_range}</span>` : ''}
   443→        </div>
   444→
   445→        ${match.match_score ? `
   446→          <div class="job-match-card ${match.match_level}">
   447→            <div class="match-header">
   448→              <span class="match-big-score">${match.match_score}%</span>
   449→              <span class="match-big-label">${match.match_level} match</span>
   450→            </div>
   451→            ${match.recommendation ? `<p class="match-recommendation">${match.recommendation}</p>` : ''}
   452→            ${match.matching_skills && match.matching_skills.length > 0 ? `
   453→              <div class="match-skills">
   454→                <strong>Matching Skills:</strong>
   455→                <div class="skill-chips">
   456→                  ${match.matching_skills.map(s => `<span class="skill-chip match">${s}</span>`).join('')}
   457→                </div>
   458→              </div>
   459→            ` : ''}
   460→            ${match.missing_skills && match.missing_skills.length > 0 ? `
   461→              <div class="match-skills">
   462→                <strong>Skills to Develop:</strong>
   463→                <div class="skill-chips">
   464→                  ${match.missing_skills.map(s => `<span class="skill-chip missing">${s}</span>`).join('')}
   465→                </div>
   466→              </div>
   467→            ` : ''}
   468→          </div>
   469→        ` : ''}
   470→
   471→        <div class="job-detail-section">
   472→          <h3>Description</h3>
   473→          <div class="job-description">${job.description || 'No description provided.'}</div>
   474→        </div>
   475→
   476→        ${job.requirements ? `
   477→          <div class="job-detail-section">
   478→            <h3>Requirements</h3>
   479→            <div class="job-requirements">${job.requirements}</div>
   480→          </div>
   481→        ` : ''}
   482→
   483→        <div class="job-detail-actions">
   484→          <button class="btn btn-ghost" onclick="toggleSave(${jobId})">
   485→            ${isSaved ? '❤️ Saved' : '🤍 Save'}
   486→          </button>
   487→          ${hasApplied ? `
   488→            <button class="btn btn-primary" disabled>Applied ✓</button>
   489→          ` : `
   490→            <button class="btn btn-primary" onclick="showApplyModal(${jobId})">Apply Now</button>
   491→          `}
   492→        </div>
   493→
   494→        <div class="job-detail-footer">
   495→          <span>Posted ${formatDate(job.created_at)}</span>
   496→        </div>
   497→      `;
   498→
   499→      panel.classList.add('active');
   500→    }
   501→
   502→    function closeDetailPanel() {
   503→      document.getElementById('job-detail-panel').classList.remove('active');
   504→    }
   505→
   506→    async function toggleSave(jobId) {
   507→      const isSaved = savedJobs.some(s => s.id === jobId);
   508→
   509→      try {
   510→        if (isSaved) {
   511→          await apiCall(`/candidate/jobs/${jobId}/save`, { method: 'DELETE' });
   512→          savedJobs = savedJobs.filter(s => s.id !== jobId);
   513→        } else {
   514→          await apiCall(`/candidate/jobs/${jobId}/save`, { method: 'POST' });
   515→          const job = allJobs.find(j => j.id === jobId);
   516→          if (job) savedJobs.push(job);
   517→        }
   518→
   519→        document.getElementById('saved-count').textContent = savedJobs.length;
   520→
   521→        // Re-render current view
   522→        if (currentTab === 'saved') {
   523→          renderSavedJobs();
   524→        } else {
   525→          renderJobs(allJobs);
   526→        }
   527→
   528→        // Update detail panel if open
   529→        if (selectedJobId === jobId) {
   530→          showJobDetail(jobId);
   531→        }
   532→      } catch (err) {
   533→        console.error('Toggle save error:', err);
   534→      }
   535→    }
   536→
   537→    function showApplyModal(jobId) {
   538→      selectedJobId = jobId;
   539→      const job = allJobs.find(j => j.id === jobId) || savedJobs.find(j => j.id === jobId);
   540→
   541→      if (!job) return;
   542→
   543→      const match = job.match || {};
   544→
   545→      document.getElementById('apply-job-title').textContent = job.title;
   546→      document.getElementById('apply-match-score').textContent = (match.match_score || 50) + '%';
   547→      document.getElementById('apply-match-level').textContent =
   548→        (match.match_level || 'fair').charAt(0).toUpperCase() + (match.match_level || 'fair').slice(1) + ' Match';
   549→      document.getElementById('apply-match-desc').textContent = 'Based on your skills and OmniScore';
   550→
   551→      const circle = document.getElementById('apply-match-circle');
   552→      circle.className = 'match-circle ' + (match.match_level || 'fair');
   553→
   554→      document.getElementById('cover-letter').value = '';
   555→
