   702→    // Initialize
   703→    document.addEventListener('DOMContentLoaded', async () => {
   704→      const user = await checkAuth();
   705→      if (!user) {
   706→        window.location.href = '/login.html';
   707→        return;
   708→      }
   709→
   710→      // Get interview ID from URL or create new
   711→      const urlParams = new URLSearchParams(window.location.search);
   712→      const jobId = urlParams.get('job_id');
   713→
   714→      // Request camera AND microphone access
   715→      try {
   716→        mediaStream = await navigator.mediaDevices.getUserMedia({
   717→          video: { width: 1280, height: 720 },
   718→          audio: {
   719→            echoCancellation: true,
   720→            noiseSuppression: true,
   721→            autoGainControl: true
   722→          }
   723→        });
   724→        document.getElementById('preview-video').srcObject = mediaStream;
   725→        document.getElementById('preview-overlay').style.display = 'none';
   726→
   727→        // Verify audio tracks are present and active
   728→        const audioTracks = mediaStream.getAudioTracks();
   729→        if (audioTracks.length === 0) {
   730→          console.error('No audio tracks in stream');
   731→          updateMicStatus('error', 'Microphone not detected');
   732→        } else {
   733→          const audioTrack = audioTracks[0];
   734→          console.log('Audio track:', audioTrack.label, 'enabled:', audioTrack.enabled, 'muted:', audioTrack.muted);
   735→
   736→          if (!audioTrack.enabled) {
   737→            audioTrack.enabled = true;
   738→          }
   739→
   740→          updateMicStatus('active', `Mic: ${audioTrack.label || 'Active'}`);
   741→
   742→          // Start audio level visualization
   743→          startAudioLevelMeter(mediaStream);
   744→        }
   745→
   746→        // Initialize video analyzer
   747→        videoAnalyzer = new VideoAnalyzer();
   748→        const initialized = await videoAnalyzer.init();
   749→
   750→        if (initialized) {
   751→          console.log('Video analyzer ready');
   752→
   753→          // Listen for live score updates
