   759→        }
   760→      } catch (err) {
   761→        console.error('Camera/microphone access error:', err);
   762→        if (err.name === 'NotAllowedError') {
   763→          alert('Camera and microphone access is required for video interviews. Please allow both permissions and reload the page.');
   764→        } else if (err.name === 'NotFoundError') {
   765→          alert('Camera or microphone not found. Please connect your devices and reload.');
   766→        } else {
