   873→    function startRecording() {
   874→      recordedChunks = [];
   875→
   876→      try {
   877→        // Use mimeType with both video AND audio codecs
   878→        let mimeType = 'video/webm;codecs=vp9,opus';
   879→        if (!MediaRecorder.isTypeSupported(mimeType)) {
   880→          mimeType = 'video/webm;codecs=vp8,opus';
   881→        }
   882→        if (!MediaRecorder.isTypeSupported(mimeType)) {
   883→          mimeType = 'video/webm';
   884→        }
   885→        console.log('Recording with mimeType:', mimeType);
   886→
   887→        // Verify audio tracks before recording
   888→        const audioTracks = mediaStream.getAudioTracks();
   889→        if (audioTracks.length === 0 || !audioTracks[0].enabled) {
   890→          alert('Microphone is not active. Please check your mic permissions and try again.');
   891→          return;
   892→        }
   893→
   894→        mediaRecorder = new MediaRecorder(mediaStream, { mimeType });
