   973→      const retakesForQuestion = retakesUsed[currentQuestionIndex] || 0;
   974→      if (retakesForQuestion >= 1) {
   975→        retakeBtn.disabled = true;
   976→        retakeBtn.textContent = '🔄 No retakes remaining';
   977→      } else {
   978→        retakeBtn.disabled = false;
   979→        retakeBtn.textContent = `🔄 Retake (${1 - retakesForQuestion} remaining)`;
   980→      }
   981→
   982→      showState('review');
   983→
   984→      // Store the blob temporarily
   985→      window.currentRecordingBlob = blob;
   986→    }
