  1126→    function updateProgress() {
  1127→      const completed = responses.filter(r => r !== null).length;
  1128→      const total = questions.length;
  1129→      const percent = total > 0 ? (completed / total) * 100 : 0;
  1130→
  1131→      document.getElementById('progress-fill').style.width = `${percent}%`;
