   411→    // Next question
   412→    function nextQuestion() {
   413→      document.getElementById('feedback-modal').classList.remove('show');
   414→      displayQuestion();
   415→      timeRemaining = currentQuestion.timeLimit;
   416→      startTimer(currentQuestion.timeLimit);
